   472→    /**
   473→     * Validates the values of the given properties. Can be called by both client and server.
   474→     * The `props` supplied should contain all the LogConfig properties and the default values are extracted from the
   475→     * LogConfig class.
   476→     * @param props The properties to be validated
   477→     */
   478→    public static void validateValues(Map<?, ?> props) {
   479→        long minCompactionLag = (Long) props.get(TopicConfig.MIN_COMPACTION_LAG_MS_CONFIG);
   480→        long maxCompactionLag = (Long) props.get(TopicConfig.MAX_COMPACTION_LAG_MS_CONFIG);
   481→        if (minCompactionLag > maxCompactionLag) {
   482→            throw new InvalidConfigurationException("conflict topic config setting "
   483→                    + TopicConfig.MIN_COMPACTION_LAG_MS_CONFIG + " (" + minCompactionLag + ") > "
   484→                    + TopicConfig.MAX_COMPACTION_LAG_MS_CONFIG + " (" + maxCompactionLag + ")");
   485→        }
   486→    }
