   578→    private static void validateRemoteStorageRetentionSize(Map<?, ?> props) {
   579→        Long retentionBytes = (Long) props.get(TopicConfig.RETENTION_BYTES_CONFIG);
   580→        Long localRetentionBytes = (Long) props.get(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG);
   581→        if (retentionBytes > -1 && localRetentionBytes != -2) {
   582→            if (localRetentionBytes == -1) {
   583→                String message = String.format("Value must not be -1 as %s value is set as %d.",
   584→                        TopicConfig.RETENTION_BYTES_CONFIG, retentionBytes);
   585→                throw new ConfigException(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG, localRetentionBytes, message);
   586→            }
   587→            if (localRetentionBytes > retentionBytes) {
   588→                String message = String.format("Value must not be more than %s property value: %d",
   589→                        TopicConfig.RETENTION_BYTES_CONFIG, retentionBytes);
   590→                throw new ConfigException(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG, localRetentionBytes, message);
   591→            }
   592→        }
   593→    }
   594→
   595→    private static void validateRemoteStorageRetentionTime(Map<?, ?> props) {
   596→        Long retentionMs = (Long) props.get(TopicConfig.RETENTION_MS_CONFIG);
   597→        Long localRetentionMs = (Long) props.get(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG);
   598→        if (retentionMs != -1 && localRetentionMs != -2) {
   599→            if (localRetentionMs == -1) {
   600→                String message = String.format("Value must not be -1 as %s value is set as %d.",
   601→                        TopicConfig.RETENTION_MS_CONFIG, retentionMs);
   602→                throw new ConfigException(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG, localRetentionMs, message);
